import{_ as a,o as r,c as t,ae as s}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"AIO Hub 架构概览 (Architecture Overview)","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/overview.md","filePath":"architecture/overview.md"}'),n={name:"architecture/overview.md"};function o(i,e,l,c,d,u){return r(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="aio-hub-架构概览-architecture-overview" tabindex="-1">AIO Hub 架构概览 (Architecture Overview) <a class="header-anchor" href="#aio-hub-架构概览-architecture-overview" aria-label="Permalink to &quot;AIO Hub 架构概览 (Architecture Overview)&quot;">​</a></h1><p>本文档旨在详尽阐述 AIO Hub 的核心设计理念、全栈技术架构、关键子系统实现及工程化规范，为开发者提供深度的技术蓝图。</p><hr><h2 id="_1-项目愿景与设计理念-philosophy" tabindex="-1">1. 项目愿景与设计理念 (Philosophy) <a class="header-anchor" href="#_1-项目愿景与设计理念-philosophy" aria-label="Permalink to &quot;1. 项目愿景与设计理念 (Philosophy)&quot;">​</a></h2><p>AIO Hub 不仅仅是一个工具集合，它是一个以开发者为中心、高度模块化且隐私优先的智能助手平台。</p><ul><li><strong>离线优先 (Offline First)</strong>: 核心能力（OCR、正则、文件处理、代码格式化）均提供本地引擎支持，确保在无网环境下依然可用，且数据不离端。</li><li><strong>透明化 (Transparency)</strong>: 拒绝“黑盒”操作。通过全链路日志 (<code>logger</code>) 和标准化错误处理 (<code>errorHandler</code>)，让每一个任务的进度、中间结果和异常都清晰可见。</li><li><strong>插件化 (Extensibility)</strong>: 核心功能与 UI 解耦，通过统一的服务注册机制，支持 JS、Native 和 Sidecar 插件扩展。</li><li><strong>多端对等 (Multi-Platform)</strong>: 桌面端与移动端共享核心逻辑架构，但在 UI 交互上针对平台特性进行深度重构。</li></ul><hr><h2 id="_2-全栈技术栈-tech-stack" tabindex="-1">2. 全栈技术栈 (Tech Stack) <a class="header-anchor" href="#_2-全栈技术栈-tech-stack" aria-label="Permalink to &quot;2. 全栈技术栈 (Tech Stack)&quot;">​</a></h2><h3 id="_2-1-基础运行时" tabindex="-1">2.1 基础运行时 <a class="header-anchor" href="#_2-1-基础运行时" aria-label="Permalink to &quot;2.1 基础运行时&quot;">​</a></h3><ul><li><strong>框架</strong>: <a href="https://tauri.app/" target="_blank" rel="noreferrer">Tauri v2</a> (Rust + WebView) <ul><li><strong>后端 (Rust)</strong>: 处理文件系统、系统原生 API（如 Windows OCR）、全局输入监听 (<code>rdev</code>)、文件回收站 (<code>trash</code>)、高性能计算。</li><li><strong>前端 (Vue 3)</strong>: 负责 UI 渲染与业务逻辑编排。</li></ul></li><li><strong>包管理器</strong>: <a href="https://bun.sh/" target="_blank" rel="noreferrer">Bun</a> (用于快速安装与脚本运行)。</li></ul><h3 id="_2-2-前端架构-pc-端" tabindex="-1">2.2 前端架构 (PC 端) <a class="header-anchor" href="#_2-2-前端架构-pc-端" aria-label="Permalink to &quot;2.2 前端架构 (PC 端)&quot;">​</a></h3><ul><li><strong>UI 框架</strong>: <a href="https://element-plus.org/" target="_blank" rel="noreferrer">Element Plus</a> + <a href="https://lucide.dev/" target="_blank" rel="noreferrer">lucide-vue-next</a>。</li><li><strong>数据可视化与增强</strong>: <a href="https://echarts.apache.org/" target="_blank" rel="noreferrer">ECharts</a> (图表), <a href="https://mermaid.js.org/" target="_blank" rel="noreferrer">Mermaid</a> (流程图), <a href="https://katex.org/" target="_blank" rel="noreferrer">KaTeX</a> (数学公式), <a href="https://vueflow.dev/" target="_blank" rel="noreferrer">@vue-flow/core</a> (节点编辑器)。</li><li><strong>状态管理</strong>: <a href="https://pinia.vuejs.org/" target="_blank" rel="noreferrer">Pinia</a> (用于全局配置、工具状态、用户 Profile)。</li><li><strong>核心工具库</strong>: <code>@vueuse/core</code> (响应式能力), <code>lodash-es</code> (工具函数), <code>markdown-it</code> (文档渲染), <code>dompurify</code> (安全净化)。</li></ul><h3 id="_2-3-前端架构-移动端" tabindex="-1">2.3 前端架构 (移动端) <a class="header-anchor" href="#_2-3-前端架构-移动端" aria-label="Permalink to &quot;2.3 前端架构 (移动端)&quot;">​</a></h3><ul><li><strong>UI 框架</strong>: <a href="https://varlet.gitee.io/varlet-ui/" target="_blank" rel="noreferrer">@varlet/ui</a> (Material Design 3 风格)。</li><li><strong>设计原则</strong>: 逻辑函数化 (Functional Core)，减少对 Vue 生命周期钩子的重度依赖，便于逻辑在多端间复用。</li></ul><hr><h2 id="_3-核心子系统架构-core-subsystems" tabindex="-1">3. 核心子系统架构 (Core Subsystems) <a class="header-anchor" href="#_3-核心子系统架构-core-subsystems" aria-label="Permalink to &quot;3. 核心子系统架构 (Core Subsystems)&quot;">​</a></h2><h3 id="_3-1-统一执行器与服务注册-unified-executor-registry" tabindex="-1">3.1 统一执行器与服务注册 (Unified Executor &amp; Registry) <a class="header-anchor" href="#_3-1-统一执行器与服务注册-unified-executor-registry" aria-label="Permalink to &quot;3.1 统一执行器与服务注册 (Unified Executor &amp; Registry)&quot;">​</a></h3><p>项目采用高度解耦的服务化架构，通过 <code>src/services/</code> 建立了一套标准化的工具间通信机制。</p><ul><li><strong>统一执行器 (Executor)</strong>: 位于 <code>src/services/executor.ts</code>，是 UI 层与业务逻辑层的核心桥梁。程序通过发送 <code>ToolCall</code> 请求并返回 <code>ServiceResult</code>，实现调用者与实现者的彻底解耦。支持开发模式下的 <code>-dev</code> 实例自动路由。</li><li><strong>自动扫描注册 (Auto Register)</strong>: <code>src/services/auto-register.ts</code> 是应用初始化的核心入口，利用 Vite 的 <code>import.meta.glob</code> 机制扫描 <code>src/tools/</code> 下所有 <code>.registry.ts</code> 模块，并依次完成：① 将 <code>toolConfig</code> 注册到 <code>toolsStore</code>（UI 工具注册）；② 实例化并注册实现了 <code>ToolRegistry</code> 接口的服务类；③ 调用 <code>pluginManager</code> 加载所有外部插件；④ 初始化工具排序并标记 store 就绪。</li><li><strong>双轨注册约定 (Registry Convention)</strong>: 每个 <code>.registry.ts</code> 文件导出两类内容——<code>toolConfig</code>（必选，供 UI 发现与渲染）和默认导出的 <code>ToolRegistry</code> 实现类（可选，仅需对外暴露编程接口的工具才提供，实现&quot;工具即服务&quot;）。</li></ul><h3 id="_3-2-插件化适配器架构-plugin-adapter-architecture" tabindex="-1">3.2 插件化适配器架构 (Plugin Adapter Architecture) <a class="header-anchor" href="#_3-2-插件化适配器架构-plugin-adapter-architecture" aria-label="Permalink to &quot;3.2 插件化适配器架构 (Plugin Adapter Architecture)&quot;">​</a></h3><p>系统通过三层适配器模式满足不同场景的扩展需求，统一包装为 <code>PluginProxy</code>：</p><ul><li><strong>JS Adapter</strong>: 处理 ESM 动态导入的前端逻辑，支持 <code>logicHook</code> 注入。</li><li><strong>Native Adapter</strong>: 桥接 Rust 编写的原生插件能力。</li><li><strong>Sidecar Adapter</strong>: 管理独立的二进制子进程（如 Python/Go 程序），通过标准 IO 或网络协议通信。</li></ul><h3 id="_3-3-llm-基础设施-llm-infrastructure" tabindex="-1">3.3 LLM 基础设施 (LLM Infrastructure) <a class="header-anchor" href="#_3-3-llm-基础设施-llm-infrastructure" aria-label="Permalink to &quot;3.3 LLM 基础设施 (LLM Infrastructure)&quot;">​</a></h3><ul><li><strong>多模态协议栈</strong>: 统一的 <code>LlmMessageContent</code> 协议，原生支持文本、图像、音频、视频及 PDF 文档的混合输入。针对不同厂商（如 Gemini 视频采样、Claude Files API）进行深度适配。</li><li><strong>深度思考与推理 (Reasoning)</strong>: <ul><li><strong>双流并行</strong>: 全链路支持 <code>Content</code> 与 <code>Reasoning</code> (思考流) 独立解析，适配 DeepSeek R1、OpenAI o-series、Gemini Thinking 等推理模型。</li><li><strong>精细化控制</strong>: 针对不同架构提供 <code>Thinking Budget</code> (Token 限制) 或 <code>Reasoning Effort</code> (强度等级) 的自适应配置。</li></ul></li><li><strong>能力感知参数过滤</strong>: 具备模型能力 (Capabilities) 感知，根据模型是否支持 Vision、Tool Use、FIM 等特性自动过滤/降级请求参数，确保 API 调用稳定性。</li><li><strong>增强特性</strong>: <ul><li><strong>前缀续写 (Prefill)</strong>: 支持 Claude/DeepSeek 的 Assistant 消息续写，实现引导式生成。</li><li><strong>Responses 有状态 API</strong>: 适配 OpenAI 新一代 Responses 接口，内置联网搜索与文件检索增强。</li></ul></li><li><strong>高可用 Key 调度</strong>: 内置多 Key 轮询与健康状态检测，具备自动熔断与成功率反馈机制。</li></ul><h3 id="_3-4-跨窗口分离架构-window-detachment-architecture" tabindex="-1">3.4 跨窗口分离架构 (Window Detachment Architecture) <a class="header-anchor" href="#_3-4-跨窗口分离架构-window-detachment-architecture" aria-label="Permalink to &quot;3.4 跨窗口分离架构 (Window Detachment Architecture)&quot;">​</a></h3><p>项目通过独立的根容器组件实现窗口分离，避免在 <code>App.vue</code> 中进行复杂的环境判断：</p><ul><li><strong>分离容器 (Views)</strong>: <ul><li><strong>工具分离</strong>: 由 <code>src/views/DetachedWindowContainer.vue</code> 承载，根据路由参数动态加载工具组件。</li><li><strong>组件分离</strong>: 由 <code>src/views/DetachedComponentContainer.vue</code> 承载，实现 UI 片段（如 ChatArea）的透明悬浮。</li></ul></li><li><strong>状态同步与生命周期</strong>: <ul><li><strong>预览与固化</strong>: 窗口在拖拽过程中处于 <code>isPreview</code> 预览状态，通过 <code>finalize_detach_session</code> 固化为最终模式。</li><li><strong>Window Sync Bus</strong>: 提供基于 Tauri Event 的跨窗口同步总线，负责握手、全量状态同步及增量 Patch 更新。</li><li><strong>逻辑挂载</strong>: 通过 <code>logicHook</code> 和 <code>initializeEnvironment</code> 确保分离窗口拥有与主窗口一致的业务逻辑上下文。</li></ul></li></ul><h3 id="_3-5-主题与质感系统-theme-appearance" tabindex="-1">3.5 主题与质感系统 (Theme Appearance) <a class="header-anchor" href="#_3-5-主题与质感系统-theme-appearance" aria-label="Permalink to &quot;3.5 主题与质感系统 (Theme Appearance)&quot;">​</a></h3><ul><li><strong>多层级视觉引擎</strong>: <ul><li><strong>原生融合</strong>: 深度集成 Windows Mica/Acrylic 和 macOS Vibrancy 效果。</li><li><strong>毛玻璃特效 (Glassmorphism)</strong>: 通过 <code>backdrop-filter</code> 与动态 CSS 变量 (<code>--ui-blur</code>, <code>--card-opacity</code>) 实现细腻的通透感。</li></ul></li><li><strong>智能壁纸系统</strong>: <ul><li><strong>全场景适配</strong>: 支持静态壁纸、目录轮播及内置精选库。</li><li><strong>色彩算法</strong>: 内置智能取色引擎，根据壁纸主色调自动计算并注入 UI 叠加色（Overlay），确保视觉一致性且不“刺眼”。</li></ul></li><li><strong>高度定制化 (Custom CSS)</strong>: <ul><li><strong>运行时覆盖</strong>: 支持用户编写自定义 CSS 片段或使用内置预设（如“赛博朋克”、“复古终端”），实现 UI 的深度重塑。</li></ul></li></ul><hr><h2 id="_4-目录结构与模块组织-directory-structure" tabindex="-1">4. 目录结构与模块组织 (Directory Structure) <a class="header-anchor" href="#_4-目录结构与模块组织-directory-structure" aria-label="Permalink to &quot;4. 目录结构与模块组织 (Directory Structure)&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>aio-hub/</span></span>
<span class="line"><span>├── src/                    # PC 端前端源码</span></span>
<span class="line"><span>│   ├── tools/              # 工具特区：包含工具组件、Store 及 \`.registry.ts\` 服务定义</span></span>
<span class="line"><span>│   ├── services/           # 核心基础设施：执行器、适配器、注册表、插件管理</span></span>
<span class="line"><span>│   ├── llm-apis/           # LLM 适配层：统一协议转换与厂商适配</span></span>
<span class="line"><span>│   ├── composables/        # 组合式逻辑：跨窗口分离、资产管理、主题系统等</span></span>
<span class="line"><span>│   ├── config/             # 全局配置与 Agent 预设 (YAML/JSON)</span></span>
<span class="line"><span>│   ├── views/              # 顶层视图容器：主窗口及各类分离窗口容器</span></span>
<span class="line"><span>│   ├── components/         # 通用 UI 组件库 (common/icons)</span></span>
<span class="line"><span>│   └── stores/             # 全局状态管理 (Pinia)</span></span>
<span class="line"><span>├── mobile/                 # 移动端项目 (Vue 3 + Varlet + Tauri)</span></span>
<span class="line"><span>│   ├── src/tools/          # 移动端适配工具 (llm-api, llm-chat 等)</span></span>
<span class="line"><span>│   └── src/utils/          # 移动端基础设施 (与 PC 端接口对齐)</span></span>
<span class="line"><span>├── src-tauri/              # Rust 核心：命令定义 (commands/)、系统集成、插件载体</span></span>
<span class="line"><span>├── plugins/                # 外部插件存放目录</span></span>
<span class="line"><span>├── docs/                   # 深度文档库</span></span>
<span class="line"><span>│   ├── architecture/       # 子系统详细设计 (Sync, Theme, LLM)</span></span>
<span class="line"><span>│   ├── design/             # 功能 RFC 与草案</span></span>
<span class="line"><span>│   └── guide/              # 开发者上手指南</span></span>
<span class="line"><span>└── scripts/                # 自动化脚本：i18n 检查、便携版构建等</span></span></code></pre></div><hr><h2 id="_5-开发者导航-navigation" tabindex="-1">5. 开发者导航 (Navigation) <a class="header-anchor" href="#_5-开发者导航-navigation" aria-label="Permalink to &quot;5. 开发者导航 (Navigation)&quot;">​</a></h2><ul><li>想要了解如何开发新工具？请参考 <a href="./docs/guide/adding-new-tool.html">新工具开发指南</a>。</li><li>对插件系统感兴趣？阅读 <a href="./docs/guide/plugin-development-guide.html">插件开发深度手册</a>。</li><li>需要处理窗口分离？查看 <a href="./docs/architecture/window-sync-architecture.html">窗口同步技术内幕</a>。</li><li>关于日志与错误处理的细节？参见 <a href="./docs/guide/logging-error-handling.html">日志与错误处理规范</a>。</li></ul>`,35)])])}const g=a(n,[["render",o]]);export{h as __pageData,g as default};
